import boto3
import json

def process_message(message):
    # Example processing logic based on message type
    message_type = message.get('Type')
    if message_type == 'TaskA':
        task_a(message)
    elif message_type == 'TaskB':
        task_b(message)
    else:
        print(f"Unknown message type: {message_type}")

def task_a(message):
    # Process Task A specific logic
    print("Processing Task A")
    print(json.dumps(message, indent=2))

def task_b(message):
    # Process Task B specific logic
    print("Processing Task B")
